// AUTO-GENERATED by Frontend Engineer workflow — DO NOT EDIT MANUALLY
import React, { useState, useEffect } from 'react';
import { shadcnComponents } from '@json-render/shadcn';
import { useStateStore } from '@json-render/react';
import type { ComponentType } from 'react';

// ────────────────────────────────────────────────────────────────────────────────
// Adapter: bridges @json-render/react's ComponentRenderProps  { element, children, emit, on, bindings, loading }
//          to   @json-render/shadcn's BaseComponentProps       { props, children, emit, on, bindings, loading }
// ────────────────────────────────────────────────────────────────────────────────
function adapt(Comp: ComponentType<any>): ComponentType<any> {
  const Adapted: ComponentType<any> = ({ element, children, emit, on, bindings, loading }: any) => {
    let store: any;
    try {
      store = useStateStore();
    } catch (e) {
      console.error('useStateStore error in adapt:', e);
      store = null;
    }

    const customEmit = (eventName: string, ...args: any[]) => {
      if (eventName === 'press' && store) {
        const label = element?.props?.label ?? '';
        const id = element?.props?.id ?? '';

        if (
          label.includes('建立') ||
          label.includes('新增') ||
          id.includes('create') ||
          id.includes('add')
        ) {
          // Skip semester and class since they are handled page-locally
          if (
            label.includes('學期') || id.includes('semester') ||
            label.includes('班級') || id.includes('class')
          ) {
            // Handled page-locally
          } else {
            const selected = store.get('/selected') || {};
            const updatedSelected = { ...selected };
            if (label.includes('學生') || id.includes('student')) {
              updatedSelected.studentId = null;
            } else if (label.includes('成績項目') || id.includes('grade-item') || id.includes('gradeItem')) {
              updatedSelected.gradeItemId = null;
            } else {
              Object.keys(updatedSelected).forEach((k) => {
                updatedSelected[k] = null;
              });
            }
            store.set('/selected', updatedSelected);
            store.set('/form', {});
          }
        }

        if (
          label === '取消' || 
          id.includes('cancel') || 
          label === '儲存' || 
          label === '確認刪除' || 
          id.includes('submit') || 
          id.includes('confirm')
        ) {
          const modals = store.get('/modals') || {};
          const updated = { ...modals };
          Object.keys(updated).forEach((k) => {
            updated[k] = false;
          });
          store.set('/modals', updated);
        }
      }

      if (emit) {
        emit(eventName, ...args);
      }
    };

    const rawProps = element?.props ?? {};
    const props = { ...rawProps };

    // Dynamic curly-brace interpolation (e.g. {{state.data.getSemesterById?.name ...}})
    if (store) {
      const interpolate = (val: any): any => {
        if (typeof val !== 'string') return val;
        return val.replace(/\{\{([^}]+)\}\}/g, (_, expression) => {
          const trimmed = expression.trim();
          if (trimmed.includes('getSemesterById')) {
            const semester = store.get('/data/getSemesterById');
            return semester?.name || semester?.label || '';
          }
          if (trimmed.includes('getClassById')) {
            const classVal = store.get('/data/getClassById');
            return classVal?.name || classVal?.label || '';
          }
          return '';
        });
      };
      if (props.text) props.text = interpolate(props.text);
      if (props.label) props.label = interpolate(props.label);
      if (props.placeholder) props.placeholder = interpolate(props.placeholder);
    }

    if (element?.type === 'Button') {
      const v = props.variant;
      if (v === 'primary') {
        props.variant = 'default';
        props.className = `${props.className || ''} bg-primary`.trim();
      } else if (v === 'danger') {
        props.variant = 'destructive';
        props.className = `${props.className || ''} bg-danger`.trim();
      } else if (v === 'secondary') {
        props.variant = 'secondary';
        props.className = `${props.className || ''} bg-secondary`.trim();
      } else if (v === 'outline') {
        props.variant = 'outline';
      } else if (!v) {
        if (props.id?.includes('link') || props.id?.includes('crumb') || props.id?.includes('breadcrumb')) {
          props.variant = 'link';
        } else {
          props.variant = 'default';
          props.className = `${props.className || ''} bg-primary`.trim();
        }
      }
      props['data-variant'] = props.variant;
    }

    return React.createElement(Comp, {
      props,
      children,
      emit: customEmit,
      on,
      bindings,
      loading,
    });
  };
  Adapted.displayName = `Adapted(${(Comp as any).displayName || Comp.name || 'Component'})`;
  return Adapted;
}

// ────────────────────────────────────────────────────────────────────────────────
// Custom composite components (ComponentRenderProps signature: { element, children, ... })
// ────────────────────────────────────────────────────────────────────────────────
const MetricCard: ComponentType<any> = ({ element }: any) => {
  const { label, value } = element?.props || {};
  return (
    <div className="bg-[#0f172a] border border-slate-800 p-6 rounded-xl shadow-lg relative overflow-hidden group hover:border-slate-700/80 transition-all duration-300">
      <div className="text-xs font-semibold tracking-wider text-slate-400 uppercase">{label}</div>
      <div className="mt-3 text-3xl font-extrabold text-white tracking-tight">{value ?? '—'}</div>
    </div>
  );
};

const DataTable: ComponentType<any> = ({ element, children, bindings }: any) => {
  let store: any;
  try {
    store = useStateStore();
  } catch (e) {
    store = null;
  }

  const { columns, data: rawData, label } = element?.props || {};
  
  // Resolve data:
  // 1. Try bindings (passed by json-render parser)
  // 2. Try resolving $bindState directly from the store
  // 3. Fallback to rawData
  let data = bindings?.data ?? rawData;
  if (typeof data === 'string' && data.startsWith('/') && store) {
    data = store.get(data);
  } else if (data && typeof data === 'object' && '$bindState' in data && store) {
    data = store.get(data.$bindState);
  }

  const rows: any[] = Array.isArray(data) ? data : [];
  return (
    <div className="bg-[#0d1321]/80 backdrop-blur-sm border border-slate-800/80 rounded-xl overflow-hidden shadow-xl">
      <table className="w-full text-left border-collapse text-slate-300 text-sm" aria-label={label}>
        <thead className="bg-slate-900/50 text-slate-400 font-medium border-b border-slate-800/80">
          <tr>
            {columns?.map((col: any) => (
              <th key={col.field} className="px-6 py-4">{col.label}</th>
            ))}
            {children && <th className="px-6 py-4 text-right">操作</th>}
          </tr>
        </thead>
        <tbody>
          {rows.length === 0 ? (
            <tr>
              <td
                colSpan={(columns?.length || 0) + (children ? 1 : 0)}
                className="px-6 py-8 text-center text-slate-500 font-medium"
              >
                (沒有資料)
              </td>
            </tr>
          ) : (
            rows.map((row: any, idx: number) => (
              <tr key={row.id || idx} className="border-b border-slate-800/40 hover:bg-slate-900/30 transition-colors">
                {columns?.map((col: any) => (
                  <td key={col.field} className="px-6 py-4">{String(row[col.field] ?? '')}</td>
                ))}
                {children && (
                  <td className="px-6 py-4 text-right space-x-2">
                    {React.Children.map(children, (child) => {
                      if (!React.isValidElement(child)) return child;
                      return (
                        <div
                          className="inline-block"
                          onClickCapture={() => {
                            if (store && row?.id) {
                              const tableId = element?.props?.id || '';
                              const dataRef = element?.props?.dataRef || '';
                              let entity = '';
                              if (dataRef && dataRef.startsWith('list')) {
                                const raw = dataRef.slice(4);
                                const base = raw.endsWith('es') ? raw.slice(0, -2) : raw.endsWith('s') ? raw.slice(0, -1) : raw;
                                entity = base.charAt(0).toLowerCase() + base.slice(1);
                              } else if (tableId) {
                                entity = tableId.replace('-table', '').replace('-list', '');
                              }
                              if (entity) {
                                store.set(`/selected/${entity}Id`, row.id);
                              }
                            }
                          }}
                        >
                          {child}
                        </div>
                      );
                    })}
                  </td>
                )}
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
};

