// ────────────────────────────────────────────────────────────────────────────────
// DatePicker — native HTML date picker, writes to explicit storePath
// Schema props: id, label, name, storePath (e.g. "/form/start-date"), disabled
// ────────────────────────────────────────────────────────────────────────────────
const DatePicker = ({ element }: any) => {
  let store: any;
  try { store = useStateStore(); } catch { store = null; }

  const { id, label, name, storePath, disabled } = element?.props || {};

  // Local state mirrors the store — provides immediate controlled re-render
  const [localValue, setLocalValue] = useState<string>(() =>
    (storePath && store ? (store.get(storePath) as string) : '') ?? ''
  );

  const storeVal = (storePath && store ? (store.get(storePath) as string) : '') ?? '';
  useEffect(() => {
    setLocalValue(storeVal);
  }, [storeVal]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value; // always YYYY-MM-DD from native date picker
    setLocalValue(val);
    if (storePath && store) store.set(storePath, val);
  };

  return (
    <div className="grid gap-1.5">
      {label && (
        <label htmlFor={id} className="text-sm font-medium leading-none text-foreground">
          {label}
        </label>
      )}
      <input
        type="date"
        id={id}
        name={name || id}
        value={localValue}
        onChange={handleChange}
        disabled={!!disabled}
        className={
          'flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 ' +
          'text-sm text-foreground ring-offset-background cursor-pointer ' +
          'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring ' +
          'disabled:cursor-not-allowed disabled:opacity-50 [color-scheme:dark]'
        }
      />
    </div>
  );
};

// ────────────────────────────────────────────────────────────────────────────────
// Custom Button Component to bypass black-box library behavior
// ────────────────────────────────────────────────────────────────────────────────
const CustomButton: ComponentType<any> = ({ props, children, emit, loading }: any) => {
  const { id, label, variant, disabled, className } = props || {};

  // Standard interactive button classes
  let btnClasses = 'inline-flex items-center justify-center font-medium rounded-lg text-sm px-4 py-2 transition-all focus:outline-none focus:ring-2 focus:ring-ring disabled:opacity-50 disabled:pointer-events-none ';
  
  if (variant === 'link') {
    btnClasses += 'text-slate-400 hover:text-slate-200 transition-colors duration-200 font-medium cursor-pointer bg-transparent border-none p-0 h-auto shadow-none text-sm ';
  } else if (variant === 'secondary') {
    btnClasses += 'bg-secondary text-slate-200 border border-slate-800/80 ';
  } else if (variant === 'destructive' || variant === 'danger') {
    btnClasses += 'bg-danger text-white shadow-lg ';
  } else if (variant === 'outline') {
    btnClasses += 'border border-slate-800 bg-transparent text-slate-200 hover:bg-slate-900/30 ';
  } else {
    // default/primary
    btnClasses += 'bg-primary text-white shadow-lg ';
  }

  if (className) {
    btnClasses += `${className} `;
  }

  const handleClick = (e: React.MouseEvent) => {
    e.preventDefault();
    if (emit) {
      emit('press');
    }
  };

  return (
    <button
      id={id}
      type="button"
      disabled={disabled || loading}
      onClick={handleClick}
      className={btnClasses.trim()}
      data-variant={variant}
    >
      {label || children}
    </button>
  );
};

// ────────────────────────────────────────────────────────────────────────────────
// Component Registry
// ────────────────────────────────────────────────────────────────────────────────
export const componentRegistry: Record<string, ComponentType<any>> = {
  // ── 1. All 36 @json-render/shadcn presets, adapted to ComponentRenderProps ──
  ...Object.fromEntries(
    Object.entries(shadcnComponents).map(([key, Comp]) => [key, adapt(Comp as ComponentType<any>)])
  ),

  // Override black-box preset button with our CustomButton to get perfect variant styling control
  'Button': adapt(CustomButton),

  // ── 2. Custom layout shell ──────────────────────────────────────────────────
  'Container:page': ({ children }) => (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6 space-y-6">{children}</div>
  ),

  // ── 3. Custom composite components ─────────────────────────────────────────
  'MetricCard': MetricCard,
  'DataTable': DataTable,
  'MultiSelect': MultiSelect,
  'Breadcrumb': Breadcrumb,
  'AlertDialog': AlertDialog,
  'DatePicker': DatePicker,

  // ── 4. Chart wrappers ───────────────────────────────────────────────────────
  'Chart:bar': ChartPlaceholder('Bar'),
  'Chart:line': ChartPlaceholder('Line'),
  'Chart:pie': ChartPlaceholder('Pie'),

  // ── 5. Native HTML wrapper (no-op passthrough) ──────────────────────────────
  'div': ({ element, children }) => (
    <div className={element?.props?.className}>{children}</div>
  ),
};
